package com.example.mpos.shift;
import android.database.Cursor;import android.os.Bundle;import android.widget.TextView;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.auth.SessionManager;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.utils.CurrencyUtils;
public class ShiftReportActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_shift_report);long u=new SessionManager(this).getUser().id;Cursor c=new DatabaseHelper(this).getReadableDatabase().rawQuery("SELECT shift_code,status,opening_cash,expected_cash,actual_cash,difference_amount,handover_note FROM shifts WHERE user_id=? ORDER BY id DESC LIMIT 1",new String[]{String.valueOf(u)});String s="Chưa có dữ liệu ca";try{if(c.moveToFirst())s="Ca: "+c.getString(0)+"\nTrạng thái: "+c.getString(1)+"\nTiền đầu ca: "+CurrencyUtils.vnd(c.getLong(2))+"\nTiền dự kiến: "+CurrencyUtils.vnd(c.getLong(3))+"\nTiền thực tế: "+CurrencyUtils.vnd(c.getLong(4))+"\nChênh lệch: "+CurrencyUtils.vnd(c.getLong(5))+"\n\nBàn giao: "+(c.getString(6)==null?"Không có":c.getString(6));}finally{c.close();}((TextView)findViewById(R.id.txtShiftReport)).setText(s);findViewById(R.id.btnBack).setOnClickListener(v->finish());}}
